import React, { useState, useEffect, useCallback, useRef } from "react";
import { useParams, useLocation, useNavigate } from "react-router-dom";
import api from "../utils/api";
import { ScoreEngine, formatTime, DIFFICULTY_COLORS } from "../utils/algorithms";
import { useAuth } from "../context/AuthContext";

const QUESTION_COUNT = 10;

export default function QuizPage() {
  const { topicId }   = useParams();
  const { state }     = useLocation();
  const navigate      = useNavigate();
  const { updateScore } = useAuth();

  const [phase,      setPhase]      = useState("loading"); // loading | ready | question | finished
  const [questions,  setQuestions]  = useState([]);
  const [topic,      setTopic]      = useState(state?.topic || null);
  const [current,    setCurrent]    = useState(0);
  const [selected,   setSelected]   = useState(null);   // chosen option index
  const [revealed,   setRevealed]   = useState(false);  // show answer
  const [timeLeft,   setTimeLeft]   = useState(30);
  const [answers,    setAnswers]     = useState([]);     // collected answers
  const [scoreState, setScoreState] = useState({ totalScore: 0, currentStreak: 0, maxStreak: 0 });
  const [lastChange, setLastChange] = useState(null);   // animated score delta
  const [sortByDiff, setSortByDiff] = useState(false);
  const [error,      setError]      = useState("");

  const engineRef   = useRef(new ScoreEngine());
  const timerRef    = useRef(null);
  const startTimeRef = useRef(Date.now());

  // ── Fetch questions ─────────────────────────────────────────────────────
  const startQuiz = useCallback(async () => {
    setPhase("loading");
    setError("");
    engineRef.current = new ScoreEngine();
    setAnswers([]);
    setCurrent(0);
    setScoreState({ totalScore: 0, currentStreak: 0, maxStreak: 0 });

    try {
      const { data } = await api.post("/quiz/start", {
        topicId,
        count: QUESTION_COUNT,
        sortByDifficulty: sortByDiff,
      });
      setQuestions(data.questions);
      setTopic(data.topic);
      setPhase("ready");
    } catch (err) {
      setError(err.response?.data?.error || "Failed to load quiz. Please try again.");
      setPhase("error");
    }
  }, [topicId, sortByDiff]);

  useEffect(() => { startQuiz(); }, [startQuiz]);

  // ── Timer per question ──────────────────────────────────────────────────
  useEffect(() => {
    if (phase !== "question" || revealed) return;

    const limit = questions[current]?.timeLimitSeconds || 30;
    setTimeLeft(limit);

    timerRef.current = setInterval(() => {
      setTimeLeft((t) => {
        if (t <= 1) {
          clearInterval(timerRef.current);
          handleTimeout();
          return 0;
        }
        return t - 1;
      });
    }, 1000);

    return () => clearInterval(timerRef.current);
  }, [phase, current, revealed]); // eslint-disable-line

  const handleTimeout = () => {
    if (revealed) return;
    clearInterval(timerRef.current);
    setRevealed(true);
    setSelected(-1); // -1 = timed out

    const result = engineRef.current.record(false, true);
    setScoreState(engineRef.current.getState());
    setLastChange({ value: 0, label: "⏰ Timed out" });

    setAnswers((prev) => [...prev, {
      questionId:      questions[current]._id,
      selectedOption:  -1,
      isCorrect:       false,
      timedOut:        true,
      timeTakenSeconds: questions[current]?.timeLimitSeconds || 30,
      scoreChange:     result.change,
    }]);
  };

  // const handleSelect = (optIndex) => {
  //   if (revealed) return;
  //   clearInterval(timerRef.current);

  //   const q         = questions[current];
  //   const isCorrect = optIndex === q.correctAnswer;
  //   const timeTaken = (q.timeLimitSeconds || 30) - timeLeft;

  //   setSelected(optIndex);
  //   setRevealed(true);

  //   const result = engineRef.current.record(isCorrect);
  //   setScoreState(engineRef.current.getState());

  //   // Animated score change indicator
  //   setLastChange({
  //     value: result.change,
  //     label: result.streakBonus > 0
  //       ? `+${result.base} +${result.streakBonus} 🔥 Streak!`
  //       : result.change > 0 ? `+${result.change}` : `${result.change}`,
  //   });

  //   setAnswers((prev) => [...prev, {
  //     questionId:      q._id,
  //     selectedOption:  optIndex,
  //     isCorrect,
  //     timedOut:        false,
  //     timeTakenSeconds: timeTaken,
  //     scoreChange:     result.change,
  //   }]);
  // };

  const handleSelect = (optIndex) => {
  if (revealed) return;
  clearInterval(timerRef.current);

  const q = questions[current];
  const timeTaken = (q.timeLimitSeconds || 30) - timeLeft;

  setSelected(optIndex);
  setRevealed(true);

  setAnswers((prev) => [
    ...prev,
    {
      questionId: q._id,
      selectedOption: optIndex,
      timedOut: false,
      timeTakenSeconds: timeTaken,
    },
  ]);
};

  const handleNext = () => {
    setLastChange(null);
    setSelected(null);
    setRevealed(false);

    if (current + 1 >= questions.length) {
      submitQuiz();
    } else {
      setCurrent((c) => c + 1);
    }
  };

  const submitQuiz = async () => {
    setPhase("submitting");
    try {
      const totalTime = Math.round((Date.now() - startTimeRef.current) / 1000);
      const { data } = await api.post("/quiz/submit", {
        topicId,
        answers,
        timeTakenSeconds: totalTime,
      });
      updateScore(data.newTotalScore);
      navigate("/results", { state: { result: data, topic, questions } });
    } catch (err) {
      setError("Failed to submit quiz. Please try again.");
      setPhase("question");
    }
  };

  // ── Render phases ───────────────────────────────────────────────────────
  if (phase === "loading" || phase === "submitting") {
    return (
      <div style={{ textAlign: "center", padding: "4rem" }}>
        <div className="spinner" />
        <p style={{ color: "var(--text-2)", marginTop: "1rem" }}>
          {phase === "submitting" ? "Submitting your answers…" : "Loading quiz…"}
        </p>
      </div>
    );
  }

  if (phase === "error") {
    return (
      <div className="card fade-in" style={{ maxWidth: 500, margin: "4rem auto", textAlign: "center" }}>
        <div style={{ fontSize: "2.5rem", marginBottom: "1rem" }}>⚠️</div>
        <h2 style={{ marginBottom: "0.5rem" }}>Something went wrong</h2>
        <p style={{ color: "var(--text-2)", marginBottom: "1.5rem" }}>{error}</p>
        <button className="btn btn-primary" onClick={startQuiz}>Try Again</button>
      </div>
    );
  }

  if (phase === "ready") {
    return (
      <div className="card fade-in" style={{ maxWidth: 560, margin: "3rem auto", textAlign: "center" }}>
        <div style={{ fontSize: "3rem", marginBottom: "1rem" }}>{topic?.icon || "📚"}</div>
        <h1 style={{ fontSize: "1.75rem", marginBottom: "0.5rem" }}>{topic?.name}</h1>
        <p style={{ color: "var(--text-2)", marginBottom: "2rem" }}>
          {QUESTION_COUNT} questions • Shuffled randomly • Timer per question
        </p>

        <div className="card" style={{ background: "var(--bg-3)", marginBottom: "1.5rem", textAlign: "left" }}>
          <h3 style={{ marginBottom: "0.75rem", fontSize: "0.95rem" }}>Scoring rules:</h3>
          {[
            ["✅ Correct answer", "+5 pts"],
            ["❌ Wrong answer",   "−1 pt"],
            ["🔥 3-in-a-row",    "+2 bonus"],
            ["🔥🔥 5-in-a-row",  "+5 bonus"],
          ].map(([rule, pts]) => (
            <div key={rule} style={{ display: "flex", justifyContent: "space-between", fontSize: "0.88rem", padding: "0.3rem 0", borderBottom: "1px solid var(--border)" }}>
              <span style={{ color: "var(--text-2)" }}>{rule}</span>
              <strong>{pts}</strong>
            </div>
          ))}
        </div>

        <label style={{ display: "flex", alignItems: "center", gap: "0.5rem", justifyContent: "center", marginBottom: "1.5rem", fontSize: "0.9rem", color: "var(--text-2)", cursor: "pointer" }}>
          <input
            type="checkbox"
            checked={sortByDiff}
            onChange={(e) => setSortByDiff(e.target.checked)}
            style={{ accentColor: "var(--accent)", width: 16, height: 16 }}
          />
          Sort questions easy → hard
        </label>

        <button
          className="btn btn-primary"
          style={{ width: "100%", justifyContent: "center", padding: "0.9rem" }}
          onClick={() => { startTimeRef.current = Date.now(); setPhase("question"); }}
        >
          Start Quiz ⚡
        </button>
      </div>
    );
  }

  // ── Question view ───────────────────────────────────────────────────────
  const q         = questions[current];
  const progress  = ((current) / questions.length) * 100;
  const timeLimit = q?.timeLimitSeconds || 30;
  const timeColor = timeLeft <= 5 ? "var(--error)" : timeLeft <= 10 ? "var(--warning)" : "var(--success)";

  return (
    <div className="fade-in" style={{ maxWidth: 680, margin: "0 auto" }}>
      {/* Top bar: progress + score + streak */}
      <div style={{ display: "flex", alignItems: "center", gap: "1rem", marginBottom: "1.25rem", flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: 200 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.8rem", color: "var(--text-2)", marginBottom: "0.3rem" }}>
            <span>Question {current + 1} / {questions.length}</span>
            <span>{Math.round(progress)}%</span>
          </div>
          <div className="progress-bar">
            <div className="progress-bar-fill" style={{ width: `${progress}%`, background: "var(--accent)" }} />
          </div>
        </div>

        {/* Score display */}
        <div style={{ position: "relative" }}>
          <div style={{
            background:    "var(--bg-2)", border: "1px solid var(--border)",
            borderRadius:  "var(--radius-sm)", padding: "0.5rem 1rem",
            fontFamily:    "var(--font-display)", fontWeight: 700,
          }}>
            <span style={{ color: "var(--text-3)", fontSize: "0.75rem" }}>SCORE </span>
            <span style={{ color: "var(--accent)", fontSize: "1.2rem" }}>{scoreState.totalScore}</span>
          </div>
          {lastChange && (
            <div style={{
              position:   "absolute", top: -8, right: 0,
              color:      lastChange.value > 0 ? "var(--success)" : lastChange.value < 0 ? "var(--error)" : "var(--text-2)",
              fontSize:   "0.85rem", fontWeight: 700, whiteSpace: "nowrap",
              animation:  "scoreUp 1.2s ease forwards",
            }}>
              {lastChange.label}
            </div>
          )}
        </div>

        {/* Streak badge */}
        {scoreState.currentStreak >= 2 && (
          <div style={{
            background: "rgba(245,158,11,0.15)", border: "1px solid rgba(245,158,11,0.3)",
            borderRadius: "var(--radius-sm)", padding: "0.5rem 0.9rem",
            color: "var(--warning)", fontWeight: 700, fontSize: "0.9rem",
            animation: "streakPop 0.3s ease",
          }}>
            🔥 {scoreState.currentStreak}×
          </div>
        )}
      </div>

      {/* Question card */}
      <div className="card" style={{ marginBottom: "1.25rem" }}>
        {/* Header: difficulty + timer */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "1.25rem" }}>
          <span className={`badge badge-${q.difficulty}`}>{q.difficulty}</span>

          {/* Timer ring */}
          <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
            <div style={{
              fontFamily: "var(--font-display)", fontWeight: 700,
              fontSize: "1.25rem", color: timeColor,
              transition: "color 0.3s",
            }}>
              {formatTime(timeLeft)}
            </div>
          </div>
        </div>

        {/* Timer bar */}
        <div className="progress-bar" style={{ marginBottom: "1.5rem" }}>
          <div
            className="progress-bar-fill"
            style={{
              width:      `${(timeLeft / timeLimit) * 100}%`,
              background: timeColor,
              transition: "width 1s linear, background 0.3s",
            }}
          />
        </div>

        {/* Question text */}
        <h2 style={{ fontSize: "1.2rem", lineHeight: 1.5, marginBottom: "1.5rem", fontFamily: "var(--font-display)" }}>
          {q.text}
        </h2>

        {/* Options */}
        <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
          {q.options.map((opt, i) => {
            const isSelected = selected === i;
            const isCorrect  = revealed && i === q.correctAnswer;
            const isWrong    = revealed && isSelected && !isCorrect;

            let bg     = "var(--bg-3)";
            let border = "var(--border)";
            let color  = "var(--text)";

            if (isCorrect) { bg = "rgba(34,197,94,0.12)"; border = "var(--success)";  color = "var(--success)"; }
            if (isWrong)   { bg = "rgba(239,68,68,0.12)";  border = "var(--error)";   color = "var(--error)"; }
            if (!revealed && isSelected) { bg = "var(--accent-glow)"; border = "var(--accent)"; color = "var(--accent)"; }

            return (
              <button
                key={i}
                onClick={() => handleSelect(i)}
                disabled={revealed}
                style={{
                  display:       "flex", alignItems: "center", gap: "0.75rem",
                  padding:       "0.9rem 1.1rem", borderRadius: "var(--radius-sm)",
                  border:        `1px solid ${border}`,
                  background:    bg, color,
                  fontSize:      "0.95rem", textAlign: "left",
                  cursor:        revealed ? "default" : "pointer",
                  transition:    "all 0.18s ease",
                  fontFamily:    "var(--font-body)",
                }}
              >
                <span style={{
                  width: 28, height: 28, borderRadius: "50%",
                  background: `${border}22`, border: `1px solid ${border}`,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontWeight: 700, fontSize: "0.85rem", flexShrink: 0,
                  color: border,
                }}>
                  {["A","B","C","D"][i]}
                </span>
                <span style={{ flex: 1 }}>{opt}</span>
                {isCorrect && <span>✅</span>}
                {isWrong   && <span>❌</span>}
              </button>
            );
          })}
        </div>

        {/* Explanation (shown after answer) */}
        {revealed && q.explanation && (
          <div style={{
            marginTop:   "1.25rem", padding: "0.9rem 1rem",
            background:  "var(--bg-3)", borderRadius: "var(--radius-sm)",
            borderLeft:  "3px solid var(--accent)",
            fontSize:    "0.88rem", color: "var(--text-2)", lineHeight: 1.6,
          }}>
            <strong style={{ color: "var(--text)" }}>💡 Explanation: </strong>
            {q.explanation}
          </div>
        )}
      </div>

      {/* Next button */}
      {revealed && (
        <button
          className="btn btn-primary fade-in"
          style={{ width: "100%", justifyContent: "center", padding: "0.9rem", fontSize: "1rem" }}
          onClick={handleNext}
        >
          {current + 1 >= questions.length ? "See Results 🏆" : "Next Question →"}
        </button>
      )}
    </div>
  );
}
